import{_ as d,o,c as i,a2 as r}from"./chunks/framework.C90q7Ucc.js";const p=JSON.parse('{"title":"Claude 支持 tmux provider 改动评估","description":"","frontmatter":{},"headers":[],"relativePath":"architecture/claude-tmux-provider-assessment.md","filePath":"architecture/claude-tmux-provider-assessment.md","lastUpdated":1780839435000}'),l={name:"architecture/claude-tmux-provider-assessment.md"};function t(c,e,u,a,s,m){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="claude-支持-tmux-provider-改动评估" tabindex="-1">Claude 支持 tmux provider 改动评估 <a class="header-anchor" href="#claude-支持-tmux-provider-改动评估" aria-label="Permalink to &quot;Claude 支持 tmux provider 改动评估&quot;">​</a></h1><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p>给 Claude 支持 tmux provider 属于中等偏大的功能改造，不是只把 <code>claudeProvider</code> 的枚举加上 <code>tmux</code>。好消息是 Claude JSONL mirror 已经存在，交互 runner 也已经把 Claude 非 SDK provider 当作 mirror turn，因此核心不用重写消息同步链路。主要工作集中在 provider 类型/配置入口、Claude tmux 启动与 prompt 注入、tmux 屏幕/按键控制、以及把 tmux 启动后的 Claude <code>session_id</code>/<code>cwd</code> 写回会话状态。</p><p>当前实现已把 Claude 默认 provider 收敛为 <code>tmux</code>。未显式设置 <code>runtime.claude.provider</code> 或全局 <code>CODELARK_CLAUDE_PROVIDER</code> 时，Claude Code 会优先启动可 attach 的 tmux TUI；仍可通过 <code>/provider pty</code> 或 <code>/provider sdk</code> 对当前 Claude 会话切换。</p><p>建议按两阶段实现：</p><ol><li>先做最小可用 Claude tmux provider：<code>/provider tmux</code> 可切换，启动 Claude Code TUI 到 tmux，普通消息自动注入，JSONL mirror 负责同步回复，<code>/tmux-screen</code> 可查看屏幕。</li><li>再补齐体验增强：Claude TUI onboarding/trust prompt 的 IM 确认、选择界面恢复、interrupt/stop 语义、设置 UI 和真实 e2e。</li></ol><h2 id="当前相关结构" tabindex="-1">当前相关结构 <a class="header-anchor" href="#当前相关结构" aria-label="Permalink to &quot;当前相关结构&quot;">​</a></h2><h3 id="codex-tmux-已有能力" tabindex="-1">Codex tmux 已有能力 <a class="header-anchor" href="#codex-tmux-已有能力" aria-label="Permalink to &quot;Codex tmux 已有能力&quot;">​</a></h3><ul><li><code>src/runtime/codex/tmux-provider.ts</code>：Codex tmux provider 主实现，包括 tmux session 创建、prompt 注入、Codex TUI trust/update/selection prompt 处理、session JSONL 发现和 SSE 输出。</li><li><code>src/bridge/tmux/runtime.ts</code>：Codex resume tmux 的命令构建和 ready 检测，服务 <code>/provider tmux</code> 这种“已有 thread -&gt; 启动可 attach tmux”的路径。</li><li><code>src/bridge/command/provider-settings.ts</code>：Codex <code>/provider tmux</code> 会先 bootstrap Codex thread，然后启动 tmux session，最后写入 <code>runtime.codex.provider=&#39;tmux&#39;</code> 和 <code>runtime.general.tmuxSessionName</code>。</li><li><code>src/bridge/host/manager.ts</code>：当当前会话是 Codex tmux 时，普通消息会被转成 <code>/tmux ...</code> 注入，mirror 再从 Codex JSONL 同步回复。</li></ul><h3 id="claude-已有能力" tabindex="-1">Claude 已有能力 <a class="header-anchor" href="#claude-已有能力" aria-label="Permalink to &quot;Claude 已有能力&quot;">​</a></h3><ul><li><code>src/runtime/claude/sdk-provider.ts</code>：Claude Agent SDK 路径。</li><li><code>src/runtime/claude/pty-provider.ts</code>：Claude Code TUI pty 路径，已有命令构建、ccr 环境准备、onboarding/trust prompt 自动确认、prompt 注入、JSONL session 发现、<code>captureClaudePtyScreen()</code>。</li><li><code>src/runtime/claude/session-jsonl.ts</code>：Claude JSONL 解析、session 列表、按 sessionId/cwd 查找、mirror delta 读取，已经能输出 <code>task_started/message/tool_started/tool_finished/task_complete/task_aborted</code>。</li><li><code>src/bridge/turn/interactive/runner.ts</code>：<code>activeRuntime === &#39;claude&#39; &amp;&amp; provider !== &#39;sdk&#39;</code> 已经视为 mirror turn，progress source 是 <code>claude_jsonl</code>，final source 是 <code>claude_task_complete</code>。</li><li><code>src/bridge/turn/interactive/sdk-conversation-engine.ts</code>：已经会根据 provider 返回的 SSE <code>status/result.session_id</code> 更新 <code>runtime.claude.sessionId/cwd</code>。</li></ul><h2 id="必改模块清单" tabindex="-1">必改模块清单 <a class="header-anchor" href="#必改模块清单" aria-label="Permalink to &quot;必改模块清单&quot;">​</a></h2><h3 id="_1-provider-类型、配置和持久化" tabindex="-1">1. Provider 类型、配置和持久化 <a class="header-anchor" href="#_1-provider-类型、配置和持久化" aria-label="Permalink to &quot;1. Provider 类型、配置和持久化&quot;">​</a></h3><p>已把 Claude provider 从 <code>pty|sdk</code> 扩成 <code>pty|sdk|tmux</code>：</p><ul><li><code>src/domain/session.ts</code><ul><li><code>ClaudeProviderChoice = &#39;pty&#39; | &#39;sdk&#39; | &#39;tmux&#39;</code>。</li></ul></li><li><code>src/configuration/schema.ts</code> / <code>fields.ts</code> / <code>defaults.toml</code><ul><li><code>runtime.claude.provider</code> 接受 <code>tmux</code>。</li><li>默认 TOML 把 Claude provider 设为 <code>tmux</code>。</li><li><code>CODELARK_CLAUDE_PROVIDER</code> 继续通过字段注册表和 runtime projection 导出，不恢复旧 <code>configuration/index.ts</code>。</li></ul></li><li><code>src/domain/session-runtime.ts</code><ul><li><code>getSessionClaudeProvider()</code> 接受 <code>tmux</code>。</li><li><code>setSessionClaudeProviderUpdate()</code> 类型自然跟随。</li></ul></li><li><code>src/bridge/session/support.ts</code><ul><li><code>resolveEffectiveClaudeProvider()</code> 接受全局或会话级 <code>tmux</code>。</li></ul></li><li><code>src/runtime/contracts.ts</code><ul><li><code>StreamChatParams.claudeProvider</code> 跟随扩展。</li></ul></li><li><code>src/operator-ui/application/config.ts</code><ul><li><code>mergeConfig()</code> 允许 <code>claudeProvider=&#39;tmux&#39;</code>。</li><li>payload/default 展示接受 tmux。</li></ul></li><li><code>src/operator-ui/shell.ts</code><ul><li>全局配置下拉框和帮助文案增加 Claude tmux。</li></ul></li><li><code>src/entrypoints/setup-wizard.ts</code><ul><li>Claude runtime 选择现在默认写入 <code>runtime.claude.provider=&#39;tmux&#39;</code>，后续可在 IM 或 UI 中切到 <code>pty</code> / <code>sdk</code>。</li></ul></li></ul><h3 id="_2-claude-tmux-provider-实现" tabindex="-1">2. Claude tmux provider 实现 <a class="header-anchor" href="#_2-claude-tmux-provider-实现" aria-label="Permalink to &quot;2. Claude tmux provider 实现&quot;">​</a></h3><p>建议新增 <code>src/runtime/claude/tmux-provider.ts</code>，不要直接复制整份 Codex tmux provider。可复用/抽取：</p><ul><li>从 <code>src/runtime/claude/pty-provider.ts</code> 复用或导出： <ul><li><code>buildClaudePtyCommand()</code> 的等价命令构建逻辑，最好改名为通用 <code>buildClaudeTuiCommand()</code>。</li><li><code>buildClaudePtyEnv()</code> 的环境构建。</li><li><code>hasClaudePtyTrustPrompt()</code>、<code>hasClaudePtyOnboardingPrompt()</code>、<code>hasClaudePtyInputPrompt()</code> 可改成通用 Claude TUI 检测函数。</li><li><code>writePrompt()</code> 的多行输入逻辑要改成基于 tmux send-keys 的注入。</li><li><code>findLatestClaudeSessionJsonlUpdatedAfter()</code> / <code>waitForClaudeSessionJsonlUpdatedAfter()</code> 可导出复用。</li></ul></li><li>从 <code>src/runtime/codex/tmux-provider.ts</code> 复用或抽取： <ul><li><code>injectPromptIntoTmuxPane()</code> 或 <code>tmuxCore.injectPromptIntoPane()</code>。</li><li>轮询 JSONL delta 并转换 SSE 的模式，但读取源要换成 <code>readClaudeSessionMirrorRecordDeltaByFilePath()</code>。</li><li>tmux session 生命周期、<code>CODELARK_DEBUG</code> 保留 tmux session 的调试行为。</li></ul></li></ul><p>最小实现的数据流：</p><ol><li>构建 Claude TUI 命令：<code>claude</code> 或 <code>ccr code</code>，携带 <code>--model</code>、<code>--permission-mode</code>、<code>--effort</code>。</li><li>用 <code>tmuxCore.ensureDetachedSession()</code> 启动 detached tmux。</li><li>捕获屏幕，处理 Claude onboarding/trust prompt，直到输入框 ready。</li><li>注入用户 prompt。</li><li>通过 <code>waitForClaudeSessionJsonlUpdatedAfter(cwd, promptStartedAtMs)</code> 找到本轮或当前 Claude JSONL，发出 <code>status.session_id/cwd/transcript_path</code>。</li><li>轮询 <code>readClaudeSessionMirrorRecordDeltaByFilePath()</code>，把 records 转成现有 SSE：<code>text/tool_use/tool_result/status/result/error</code>。</li><li>task complete 后关闭 stream；<code>CODELARK_DEBUG</code> 未开启时按策略决定是否 kill tmux。若目标是可 attach provider，建议不要每轮 kill，而是保留 session 并复用，类似用户期望的 tmux provider。</li></ol><h3 id="_3-路由器接入" tabindex="-1">3. 路由器接入 <a class="header-anchor" href="#_3-路由器接入" aria-label="Permalink to &quot;3. 路由器接入&quot;">​</a></h3><ul><li><code>src/runtime/codex/routing-provider.ts</code><ul><li>新增 <code>ClaudeTmuxProvider</code> 成员。</li><li><code>params.runtime === &#39;claude&#39;</code> 时把 <code>claudeProvider === &#39;tmux&#39;</code> 路由到 Claude tmux provider。</li><li>日志里 provider 输出 <code>tmux</code>。</li></ul></li></ul><h3 id="_4-provider-tmux-和普通消息转发" tabindex="-1">4. <code>/provider tmux</code> 和普通消息转发 <a class="header-anchor" href="#_4-provider-tmux-和普通消息转发" aria-label="Permalink to &quot;4. `/provider tmux` 和普通消息转发&quot;">​</a></h3><p><code>/provider</code> 在 Claude runtime 下现在接受 <code>tmux|pty|sdk</code>：</p><ul><li><code>src/bridge/command/provider-settings.ts</code><ul><li><code>CLAUDE_PROVIDER_OPTIONS_TEXT</code> 增加 <code>tmux</code>。</li><li><code>parseClaudeProviderArg()</code> 接受 <code>tmux</code>。</li><li>Claude <code>/provider tmux</code> 应启动或绑定一个 Claude tmux session，并写入： <ul><li><code>runtime.claude.provider=&#39;tmux&#39;</code></li><li><code>runtime.general.tmuxSessionName=&lt;session&gt;</code></li><li>如已发现 Claude JSONL，再写入 <code>runtime.claude.sessionId/cwd</code></li></ul></li><li>这里缺少 Claude 的“先 bootstrap thread 再 resume”的等价机制。Claude Code 可以用 <code>--resume &lt;session&gt;</code> 或类似能力时再补 resume；否则第一版可以启动空 Claude TUI，普通消息注入后发现 JSONL session。</li></ul></li><li><code>src/bridge/host/manager.ts</code><ul><li>当前普通消息自动转发到 tmux provider 的分支显式排除了 Claude：<code>activeRuntime !== &#39;claude&#39; &amp;&amp; provider === &#39;tmux&#39;</code>。</li><li>需要增加 Claude tmux 分支：当 <code>activeRuntime === &#39;claude&#39; &amp;&amp; claudeProvider === &#39;tmux&#39;</code> 时，把普通消息注入到 <code>runtime.general.tmuxSessionName</code>。</li><li>当前自动转发文案写死 Codex tmux，需要按 runtime 区分。</li><li>TUI selection prompt 恢复逻辑目前只处理 Codex TUI，Claude 需要单独处理或第一版明确不启用。</li></ul></li></ul><h3 id="_5-tmux-runtime-抽象" tabindex="-1">5. tmux runtime 抽象 <a class="header-anchor" href="#_5-tmux-runtime-抽象" aria-label="Permalink to &quot;5. tmux runtime 抽象&quot;">​</a></h3><p><code>src/bridge/tmux/runtime.ts</code> 现在是 Codex 专用的 resume 命令构建。建议拆出更通用的能力：</p><ul><li>保留 <code>codexTmuxSessionName()</code> / <code>startCodexResumeTmuxSession()</code>。</li><li>新增： <ul><li><code>claudeTmuxSessionName(bridgeSessionId or claudeSessionId)</code></li><li><code>buildClaudeTmuxCommand()</code></li><li><code>startClaudeTmuxSession()</code></li><li><code>hasClaudeTmuxReadyPrompt()</code> / <code>waitForClaudeTmuxReady()</code></li></ul></li><li>或者新增 <code>src/bridge/tmux/claude-runtime.ts</code>，避免把 Codex 参数和 Claude 参数混在同一个接口里。</li></ul><h3 id="_6-屏幕、按键和-stop-interrupt" tabindex="-1">6. 屏幕、按键和 stop/interrupt <a class="header-anchor" href="#_6-屏幕、按键和-stop-interrupt" aria-label="Permalink to &quot;6. 屏幕、按键和 stop/interrupt&quot;">​</a></h3><ul><li><code>/tmux-screen</code> 本身基于 <code>runtime.general.tmuxSessionName</code>，理论上可复用。</li><li><code>/tmux</code>、<code>/tmux-key</code> 也可复用，但文案要避免只说 Codex。</li><li><code>/pty-screen</code> 不适用于 Claude tmux，不需要改成 tmux。</li><li><code>/stop</code> 或 abort 行为需要确认： <ul><li>pty Claude 用 Ctrl-C 写到 pty。</li><li>tmux Claude 应通过 <code>tmuxCore.sendInterrupt(targetPane)</code>。</li><li>如果当前任务是 mirror turn，还要确保 session executor/turn state 能结束或等待 JSONL 出现 interrupted 记录。</li></ul></li></ul><h3 id="_7-mirror-与状态同步" tabindex="-1">7. Mirror 与状态同步 <a class="header-anchor" href="#_7-mirror-与状态同步" aria-label="Permalink to &quot;7. Mirror 与状态同步&quot;">​</a></h3><p>Claude mirror source 已经有 <code>createClaudeMirrorJsonlSource()</code>，但需要确认 host manager 是否创建了 Claude mirror runtime，以及订阅发现是否依赖 <code>runtime.claude.sessionId/cwd</code>。如果 Claude tmux 首轮没有及时写入 <code>sessionId/cwd</code>，mirror subscription 找不到源。</p><p>关键要求：</p><ul><li>Claude tmux provider 必须尽早发出 <code>status</code> 或 <code>result</code>： <ul><li><code>session_id</code></li><li><code>cwd</code></li><li><code>transcript_path</code></li></ul></li><li><code>sdk-conversation-engine.ts</code> 已会根据这些字段写回 <code>setSessionClaudeIdentityUpdate()</code>，可复用。</li><li>如果 <code>/provider tmux</code> 启动时没有 sessionId，首轮消息后才能订阅 mirror；要验证首轮是否还能被 interactive runner 的本次 provider stream 正常消费。保险做法是 provider 内部自己轮询 JSONL 并输出 SSE，而不是完全依赖后台 mirror runtime。</li></ul><h2 id="风险点" tabindex="-1">风险点 <a class="header-anchor" href="#风险点" aria-label="Permalink to &quot;风险点&quot;">​</a></h2><ul><li>Claude Code TUI 的输入 ready/onboarding/trust 文案可能随版本变化；pty 现有检测逻辑是经验规则，tmux 复用时要通过真实 CLI 验证。</li><li>Claude JSONL 文件发现依赖 cwd 到 <code>~/.claude/projects/&lt;project&gt;</code> 的映射；worktree/symlink cwd 已有兼容逻辑，但 tmux 的 <code>-c</code> cwd 必须和写入 JSONL 的 cwd 保持一致。</li><li>Claude 没有 Codex 那种已稳定使用的 <code>threadId -&gt; resume tmux session</code> 启动路径。是否支持 <code>--resume</code>、如何选择最近 session，需要单独验证 CLI 行为。</li><li>Codex tmux provider 里有大量 Codex 专属选择提示处理，不能直接套给 Claude；否则权限/更新/goal prompt 误判风险高。</li><li>当前全局配置序列化似乎没有写出 <code>CODELARK_CLAUDE_PROVIDER</code>，这会影响所有 Claude provider 默认配置持久化，需顺手修。</li><li>Windows/psmux 支持要单独确认；当前 tmux 文案兼容 psmux，但 Claude TUI 行为可能不同。</li></ul><h2 id="测试建议" tabindex="-1">测试建议 <a class="header-anchor" href="#测试建议" aria-label="Permalink to &quot;测试建议&quot;">​</a></h2><p>单元测试：</p><ul><li><code>src/__tests__/unit/configuration/config.test.ts</code><ul><li><code>CODELARK_CLAUDE_PROVIDER=tmux</code> 读取、保存、序列化。</li></ul></li><li><code>src/__tests__/unit/bridge/command/help-command.test.ts</code> 或 provider command 相关测试 <ul><li>Claude runtime 下 <code>/provider</code> 展示 <code>tmux</code>。</li><li><code>/provider tmux</code> 写入 Claude provider 和 tmux session。</li></ul></li><li><code>src/__tests__/unit/runtime/claude/*</code><ul><li>Claude tmux command 构建：<code>claude</code>、<code>ccr code</code>、model、permission mode、effort。</li><li>ready prompt/onboarding/trust prompt 检测。</li><li>JSONL delta records -&gt; SSE 映射。</li></ul></li></ul><p>Workflow 测试：</p><ul><li><code>src/__tests__/workflow/runtime/claude/claude-tmux-provider.test.ts</code><ul><li>mock tmuxCore：启动、capture、sendActions、kill/interrupt。</li><li>mock Claude JSONL：首轮发现 session_id/cwd，流式输出 assistant/tool/result。</li></ul></li><li><code>src/__tests__/workflow/bridge/command/command-dispatch.test.ts</code><ul><li>Claude runtime 下 <code>/p tmux</code>、普通消息自动转发到 tmux。</li></ul></li></ul><p>真实 e2e：</p><ul><li>新增 <code>src/__tests__/e2e/local-process/claude/real-claude-tmux-provider.e2e.test.ts</code><ul><li>需要本机安装 tmux/psmux 和 Claude Code。</li><li>验证首轮消息、继续同一 session、<code>/tmux-screen</code>、abort/interrupt。</li></ul></li></ul><h2 id="粗略工作量" tabindex="-1">粗略工作量 <a class="header-anchor" href="#粗略工作量" aria-label="Permalink to &quot;粗略工作量&quot;">​</a></h2><ul><li>最小可用：约 1.5-2.5 天。 <ul><li>类型/配置/UI/命令：0.5 天。</li><li>Claude tmux provider：0.5-1 天。</li><li>mock workflow 测试和修边：0.5-1 天。</li></ul></li><li>完整体验：约 3-5 天。 <ul><li>onboarding/trust/selection 的 IM 确认、真实 e2e、stop/interrupt、跨平台验证都需要额外时间。</li></ul></li></ul><h2 id="推荐实现顺序" tabindex="-1">推荐实现顺序 <a class="header-anchor" href="#推荐实现顺序" aria-label="Permalink to &quot;推荐实现顺序&quot;">​</a></h2><ol><li>扩展 <code>ClaudeProviderChoice</code> 和配置链路，先让 <code>tmux</code> 能被保存、展示、路由。</li><li>抽出 Claude TUI 命令/检测/JSONL 发现工具，避免 pty/tmux 复制两套。</li><li>新增 Claude tmux provider，先 provider 内部轮询 JSONL 并输出 SSE，确保首轮可用。</li><li>接入 <code>/provider tmux</code> 和普通消息 auto-forward。</li><li>补测试和文档，最后再做真实 Claude/tmux e2e。</li></ol>',47)])])}const x=d(l,[["render",t]]);export{p as __pageData,x as default};
